export const ADJACENCY = CAMPUS_EDGES.reduce(
  (acc, edge) => {
    if (!acc[edge.from]) acc[edge.from] = [];
    if (!acc[edge.to]) acc[edge.to] = [];
    acc[edge.from].push(edge.to);
    acc[edge.to].push(edge.from); // bidirectional
    return acc;
  }, {}
);
